return ['domain'=>'brikpanel','plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'es_ES','project-id-version'=>'BrikPanel','pot-creation-date'=>'2026-05-24T17:14:30+00:00','po-revision-date'=>'2026-05-23','x-generator'=>'Claude (BrikPanel auto-translation)','messages'=>['BrikPanel: WooCommerce Admin Dashboard Theme'=>'BrikPanel: WooCommerce Admin Dashboard Theme','Beautiful and modern Shopify-style WooCommerce admin panel & dashboard, fully free, forever.'=>'Panel de administración y dashboard WooCommerce moderno y bonito al estilo Shopify, totalmente gratis, para siempre.','Brksoft'=>'Brksoft','https://brksoft.com/'=>'https://brksoft.com/','WooCommerce is not active on this site, so BrikPanel features are disabled here. Activate WooCommerce to enable BrikPanel.'=>'WooCommerce no está activo en este sitio, por lo que las funciones de BrikPanel están desactivadas aquí. Activa WooCommerce para habilitar BrikPanel.','Order statusReturn Draft'=>'Borrador de devolución','Return Draft <span class="count">(%s)</span>'=>'Borrador de devolución <span class="count">(%s)</span>' . "\0" . 'Borradores de devolución <span class="count">(%s)</span>','Order statusChange'=>'Cambio','Change <span class="count">(%s)</span>'=>'Cambio <span class="count">(%s)</span>' . "\0" . 'Cambios <span class="count">(%s)</span>','Settings'=>'Ajustes','Ad Platforms integration'=>'Integración de plataformas publicitarias','Pull daily ad spend from Google Ads and Meta Ads to calculate true ROAS and Net Profit on the dashboard. Currently in beta — turn it off below to hide the admin page and stop all background sync jobs. Your connections stay saved.'=>'Importa el gasto publicitario diario desde Google Ads y Meta Ads para calcular el ROAS real y el beneficio neto en el dashboard. Actualmente en beta, desactívalo abajo para ocultar la página de administración y detener todos los trabajos de sincronización en segundo plano. Tus conexiones permanecen guardadas.','Enable Ad Platforms integration'=>'Activar integración de plataformas publicitarias','When on, the Ad Platforms admin menu, daily sync, and dashboard ROAS / Net Profit cards are active. When off, the module is dormant: no menu item, no scheduled sync, no dashboard cards.'=>'Cuando está activado, el menú de plataformas publicitarias, la sincronización diaria y las tarjetas de ROAS / beneficio neto del dashboard están activas. Cuando está desactivado, el módulo permanece inactivo: sin elemento de menú, sin sincronización programada, sin tarjetas del dashboard.','Beta'=>'Beta','ROAS'=>'ROAS','Google Ads connection was revoked for security. Please reconnect.'=>'La conexión con Google Ads se revocó por seguridad. Vuelve a conectar.','Not connected to Google Ads.'=>'No conectado a Google Ads.','The BrikPanel proxy returned an unverifiable response and was rejected.'=>'El proxy de BrikPanel devolvió una respuesta no verificable y fue rechazada.','Request to Google Ads failed after retries.'=>'La solicitud a Google Ads falló tras los reintentos.','Meta Ads connection was revoked for security. Please reconnect.'=>'La conexión con Meta Ads se revocó por seguridad. Vuelve a conectar.','Not connected to Meta Ads.'=>'No conectado a Meta Ads.','Request to Meta Ads failed after retries.'=>'La solicitud a Meta Ads falló tras los reintentos.','Permission denied.'=>'Permiso denegado.','Unknown platform.'=>'Plataforma desconocida.','This connection is not available yet — it is pending platform approval.'=>'Esta conexión aún no está disponible, está pendiente de aprobación de la plataforma.','Could not reach the BrikPanel proxy. Please try again in a moment.'=>'No se pudo contactar con el proxy de BrikPanel. Inténtalo de nuevo en un momento.','Could not start OAuth: proxy returned an error.'=>'No se pudo iniciar OAuth: el proxy devolvió un error.','Disconnected.'=>'Desconectado.','OAuth session expired. Please try connecting again.'=>'La sesión OAuth ha caducado. Intenta conectar de nuevo.','Unknown platform in OAuth state.'=>'Plataforma desconocida en el estado OAuth.','OAuth callback was for a different user. Aborted.'=>'La devolución de llamada OAuth era para otro usuario. Cancelado.','Could not reach the BrikPanel proxy.'=>'No se pudo contactar con el proxy de BrikPanel.','OAuth redemption failed. Please try connecting again.'=>'Falló el canje OAuth. Intenta conectar de nuevo.','Could not save tokens. Please try again.'=>'No se pudieron guardar los tokens. Inténtalo de nuevo.','Google Ads connected.'=>'Google Ads conectado.','Meta Ads connected.'=>'Meta Ads conectado.','Ad Platforms'=>'Plataformas publicitarias','Beta feature'=>'Función beta','Connecting…'=>'Conectando…','Disconnect this platform? Your synced spend data will be deleted.'=>'¿Desconectar esta plataforma? Los datos de gasto sincronizados se eliminarán.','Syncing…'=>'Sincronizando…','Sync queued. Refresh the page in a moment.'=>'Sincronización en cola. Actualiza la página en un momento.','Saved.'=>'Guardado.','Loading accounts…'=>'Cargando cuentas…','No ad accounts found for this connection.'=>'No se encontraron cuentas publicitarias para esta conexión.','Something went wrong. Please try again.'=>'Algo salió mal. Inténtalo de nuevo.','No errors logged.'=>'No se han registrado errores.','Connected'=>'Conectado','Not connected'=>'No conectado','Pick a primary account first.'=>'Selecciona primero una cuenta principal.','Manager'=>'Administrador','Loading history… %1$d of %2$d 90-day chunks done'=>'Cargando historial… %1$d de %2$d bloques de 90 días completados','Connect this platform first.'=>'Conecta primero esta plataforma.','Pick an account before saving.'=>'Selecciona una cuenta antes de guardar.','Account saved. Loading 3 years of history in the background — refresh the page in a few minutes to see it.'=>'Cuenta guardada. Cargando 3 años de historial en segundo plano, actualiza la página en unos minutos para verlo.','Account saved.'=>'Cuenta guardada.','Synced %1$d row(s) across %2$d day(s).'=>'Sincronizadas %1$d fila(s) a lo largo de %2$d día(s).','Ad spend daily sync'=>'Sincronización diaria de gasto publicitario','Pulls yesterday plus the last 7 days of spend from each connected ad platform.'=>'Importa el día de ayer más los últimos 7 días de gasto de cada plataforma publicitaria conectada.','Ad spend backfill chunk'=>'Bloque de relleno de gasto publicitario','One 90-day slice of the initial historical pull when an ad platform is first connected.'=>'Una porción de 90 días de la importación histórica inicial al conectar una plataforma publicitaria por primera vez.','Not connected.'=>'No conectado.','Pending Google approval'=>'Pendiente de aprobación de Google','Google Ads needs to approve our API access before this connection can go live. It will be enabled automatically once approved — no action is needed from you.'=>'Google Ads necesita aprobar nuestro acceso a la API antes de que esta conexión pueda activarse. Se habilitará automáticamente una vez aprobada, no necesitas hacer nada.','Connect Google Ads'=>'Conectar Google Ads','Pending Meta approval'=>'Pendiente de aprobación de Meta','Meta needs to review our app before this connection can go live. It will be enabled automatically once approved — no action is needed from you.'=>'Meta necesita revisar nuestra app antes de que esta conexión pueda activarse. Se habilitará automáticamente una vez aprobada, no necesitas hacer nada.','Connect Meta Ads'=>'Conectar Meta Ads','Coming soon'=>'Próximamente','BrikPanel will request read-only access to your Google Ads accounts. We only pull total daily spend, impressions and clicks — no campaign management.'=>'BrikPanel solicitará acceso de solo lectura a tus cuentas de Google Ads. Solo importamos el gasto diario total, impresiones y clics, sin gestión de campañas.','BrikPanel will request read-only access (ads_read) to your Meta ad accounts. We only pull total daily spend, impressions and clicks.'=>'BrikPanel solicitará acceso de solo lectura (ads_read) a tus cuentas publicitarias de Meta. Solo importamos el gasto diario total, impresiones y clics.','Connected as'=>'Conectado como','(email not shared)'=>'(email no compartido)','Primary ad account'=>'Cuenta publicitaria principal','BrikPanel pulls spend from this one account. To switch later, choose another from the list and click Save.'=>'BrikPanel importa el gasto de esta cuenta. Para cambiar más tarde, elige otra de la lista y haz clic en Guardar.','Click "Load accounts" to choose…'=>'Haz clic en "Cargar cuentas" para elegir…','Load accounts'=>'Cargar cuentas','Save'=>'Guardar','Manager (MCC) account ID — optional'=>'ID de cuenta de administrador (MCC), opcional','Only fill in if you access the chosen account through a Google Ads manager. Digits only, no dashes.'=>'Rellena solo si accedes a la cuenta elegida a través de un administrador de Google Ads. Solo dígitos, sin guiones.','Last successful sync'=>'Última sincronización exitosa','ago'=>'hace','(last attempt failed — check the error log)'=>'(el último intento falló, revisa el registro de errores)','Sync now'=>'Sincronizar ahora','Re-authorize'=>'Volver a autorizar','Disconnect'=>'Desconectar','Connect Google Ads and Meta Ads so BrikPanel can show real ROAS and Net Profit on the dashboard.'=>'Conecta Google Ads y Meta Ads para que BrikPanel pueda mostrar el ROAS real y el beneficio neto en el dashboard.','Google Ads'=>'Google Ads','Pulls daily total spend, impressions and clicks from one Google Ads account.'=>'Importa el gasto total diario, impresiones y clics de una cuenta de Google Ads.','Meta Ads'=>'Meta Ads','Pulls daily total spend, impressions and clicks from one Meta ad account (Facebook + Instagram).'=>'Importa el gasto total diario, impresiones y clics de una cuenta publicitaria de Meta (Facebook + Instagram).','How it works'=>'Cómo funciona','Connect each platform once. Tokens are encrypted on this server and never leave it.'=>'Conecta cada plataforma una vez. Los tokens se cifran en este servidor y nunca lo abandonan.','On first connect, the last 3 years of daily spend are loaded in the background (90-day chunks every 30 seconds).'=>'En la primera conexión, se cargan los últimos 3 años de gasto diario en segundo plano (bloques de 90 días cada 30 segundos).','After that, the last 7 days are refreshed once per day to capture late corrections.'=>'Después, los últimos 7 días se actualizan una vez al día para capturar correcciones tardías.','Spend is stored in the ad account currency — the dashboard shows ad-currency totals next to your store revenue so you can compare them directly.'=>'El gasto se almacena en la moneda de la cuenta publicitaria, el dashboard muestra los totales en la moneda publicitaria junto a los ingresos de tu tienda para que puedas compararlos directamente.','Recent errors'=>'Errores recientes','Last 50 entries from the sync log. Token values are redacted before storage.'=>'Últimas 50 entradas del registro de sincronización. Los valores de los tokens se ocultan antes de almacenarse.','View log'=>'Ver registro','Clear log'=>'Limpiar registro','System default'=>'Predeterminado del sistema','Appearance'=>'Apariencia','Customize how the BrikPanel admin interface looks. Changes apply to dashboard, products, orders, coupons, segments, the top bar, sidebar, and the modern login page. The rest of WordPress admin is untouched.'=>'Personaliza el aspecto de la interfaz de administración de BrikPanel. Los cambios se aplican al dashboard, productos, pedidos, cupones, segmentos, la barra superior, la barra lateral y la página de inicio de sesión moderna. El resto de la administración de WordPress no se ve afectada.','Interface font'=>'Tipografía de la interfaz','Pick the typeface used across BrikPanel. "System default" stays on your operating system\'s native font (no external request). Other choices load a single Google Fonts stylesheet with display: swap.'=>'Elige la tipografía usada en BrikPanel. "Predeterminada del sistema" mantiene la fuente nativa de tu sistema operativo (sin solicitudes externas). Otras opciones cargan una sola hoja de estilos de Google Fonts con display: swap.','Accent color'=>'Color de acento','Primary color used for buttons, focus rings, toggles, and active highlights. The BrikPanel default is a near-black gray (#303030); pick anything you like.'=>'Color principal usado para botones, marcos de foco, conmutadores y destacados activos. El predeterminado de BrikPanel es un gris casi negro (#303030); elige el que prefieras.','Custom brand logo'=>'Logotipo de marca personalizado','Replace the BrikPanel mark in the admin top bar and on the modern login page with your own brand logo. When off, the default BrikPanel icon and your site name are shown.'=>'Sustituye la marca de BrikPanel en la barra superior de administración y en la página de inicio de sesión moderna con tu propio logotipo. Cuando está desactivado, se muestran el icono predeterminado de BrikPanel y el nombre de tu sitio.','Brand logo image'=>'Imagen del logotipo de marca','Pick or upload an image from your media library. The same logo is used in the admin top bar and on the modern login page. PNG or SVG with transparent background gives the cleanest result. Recommended size: 256×256 px or wider.'=>'Elige o sube una imagen desde tu biblioteca de medios. El mismo logotipo se usa en la barra superior de administración y en la página de inicio de sesión moderna. PNG o SVG con fondo transparente ofrece el resultado más limpio. Tamaño recomendado: 256×256 px o más ancho.','No logo selected'=>'Ningún logotipo seleccionado','Replace logo'=>'Sustituir logotipo','Select logo'=>'Seleccionar logotipo','Remove'=>'Eliminar','Select brand logo'=>'Seleccionar logotipo de marca','Use this image'=>'Usar esta imagen','Product Image Health'=>'Salud de imágenes de productos','Scanning… %1$s / %2$s products'=>'Escaneando… %1$s / %2$s productos','No product images found yet.'=>'No se han encontrado imágenes de productos aún.','%1$s%% oversized (%2$s of %3$s) · %4$s%% modern format'=>'%1$s%% con tamaño excesivo (%2$s de %3$s) · %4$s%% en formato moderno','Add product images to start the health check.'=>'Añade imágenes de productos para iniciar el chequeo de salud.','%1$s product images are larger than 1 MB. Modern formats (WebP / AVIF) cover %2$s%% of your library. Missing files: %3$s.'=>'%1$s imágenes de productos superan 1 MB. Los formatos modernos (WebP / AVIF) cubren el %2$s%% de tu biblioteca. Archivos faltantes: %3$s.','No products yet — nothing to check.'=>'Aún no hay productos, nada que comprobar.','Add at least one published product to enable image health checks.'=>'Añade al menos un producto publicado para habilitar los chequeos de salud de imágenes.','Install %s to compress images and convert to WebP/AVIF automatically.'=>'Instala %s para comprimir imágenes y convertirlas a WebP/AVIF automáticamente.','Install plugin'=>'Instalar plugin','%1$s product images (%2$s%%) are larger than 1 MB. These slow down your product pages and hurt SEO. Compress them to under 200 KB where possible.'=>'%1$s imágenes de productos (%2$s%%) superan 1 MB. Esto ralentiza las páginas de producto y perjudica al SEO. Comprímelas a menos de 200 KB cuando sea posible.','Only %s%% of your product images use WebP / AVIF. Modern formats are 30–50%% smaller than JPEG/PNG with no visible quality loss.'=>'Solo el %s%% de tus imágenes de producto usan WebP / AVIF. Los formatos modernos son entre un 30 y un 50%% más pequeños que JPEG/PNG sin pérdida visible de calidad.','%s product images point to files that no longer exist on disk. Re-upload them or detach the missing media references.'=>'%s imágenes de producto apuntan a archivos que ya no existen en disco. Vuelve a subirlas o desvincula las referencias de medios faltantes.','Your product images are well-optimised. Keep an eye on this metric as you upload new products.'=>'Tus imágenes de productos están bien optimizadas. Vigila esta métrica a medida que subes nuevos productos.','BrikControl: Full Health Scan'=>'BrikControl: escaneo de salud completo','Runs every BrikControl check and writes results to the dashboard.'=>'Ejecuta todas las comprobaciones de BrikControl y escribe los resultados en el dashboard.','BrikControl: Scan Batch'=>'BrikControl: lote de escaneo','Processes a single batch of a long-running BrikControl check.'=>'Procesa un único lote de una comprobación larga de BrikControl.','Store Health'=>'Salud de la tienda','Rescan now'=>'Volver a escanear ahora','Scan queued — refreshing…'=>'Escaneo en cola, actualizando…','Could not start scan.'=>'No se pudo iniciar el escaneo.','Not scanned yet'=>'Aún sin escanear','Scanning in background…'=>'Escaneando en segundo plano…','just now'=>'ahora mismo','Scanning {cursor} / {total} products…'=>'Escaneando {cursor} / {total} productos…','All checks passing'=>'Todas las comprobaciones superadas','Open Store Health'=>'Abrir salud de la tienda','Last scan'=>'Último escaneo','Scanning…'=>'Escaneando…','%s min ago'=>'hace %s min' . "\0" . 'hace %s min','%s h ago'=>'hace %s h' . "\0" . 'hace %s h','%s d ago'=>'hace %s d' . "\0" . 'hace %s d','You do not have permission to access this page.'=>'No tienes permiso para acceder a esta página.','Not scanned yet — run a scan to see results.'=>'Aún sin escanear, ejecuta un escaneo para ver los resultados.','%s critical store health issue'=>'%s problema crítico de salud de la tienda' . "\0" . '%s problemas críticos de salud de la tienda','%s store health warning'=>'%s aviso de salud de la tienda' . "\0" . '%s avisos de salud de la tienda','Store health: all checks passing'=>'Salud de la tienda: todas las comprobaciones superadas','Open full report'=>'Abrir informe completo','Run a scan to see store health checks.'=>'Ejecuta un escaneo para ver las comprobaciones de salud de la tienda.','%s critical store health issue detected'=>'Se ha detectado %s problema crítico de salud de la tienda' . "\0" . 'Se han detectado %s problemas críticos de salud de la tienda','Open the BrikControl report to see what to fix and which plugins can help.'=>'Abre el informe de BrikControl para ver qué arreglar y qué plugins pueden ayudar.','View report'=>'Ver informe','Dismiss for 7 days'=>'Descartar durante 7 días','A scan is already running.'=>'Ya hay un escaneo en marcha.','Action Scheduler is unavailable.'=>'Action Scheduler no está disponible.','Scan queued.'=>'Escaneo en cola.','A scan is already in the queue.'=>'Ya hay un escaneo en la cola.','Missing dismiss target.'=>'Falta el destino del descarte.','Invalid nonce.'=>'Nonce no válido.','Last scan: %s'=>'Último escaneo: %s','No scan completed yet.'=>'Aún no se ha completado ningún escaneo.','Scan now'=>'Escanear ahora','Critical'=>'Crítico','Warnings'=>'Avisos','OK'=>'OK','Pending'=>'Pendiente','Scanning your store…'=>'Escaneando tu tienda…','No checks registered yet. Once the first scan finishes, you will see results here.'=>'Aún no hay comprobaciones registradas. Cuando termine el primer escaneo, verás los resultados aquí.','Warning'=>'Aviso','Health score'=>'Puntuación de salud','Active optimizer plugins:'=>'Plugins optimizadores activos:','Open'=>'Abrir','Total images'=>'Imágenes totales','Over 1 MB'=>'Más de 1 MB','WebP / AVIF'=>'WebP / AVIF','JPEG / PNG'=>'JPEG / PNG','Missing files'=>'Archivos faltantes','Largest images (top 10)'=>'Imágenes más grandes (top 10)','Image'=>'Imagen','Size'=>'Tamaño','Format'=>'Formato','Action'=>'Acción','(no title)'=>'(sin título)','Scanned %s'=>'Escaneado %s','Orders'=>'Pedidos','Products'=>'Productos','Analytics'=>'Analíticas','Coupons'=>'Cupones','Search coupons...'=>'Buscar cupones...','Add coupon'=>'Añadir cupón','All'=>'Todos','Published'=>'Publicado','Draft'=>'Borrador','Trash'=>'Papelera','Newest first'=>'Más recientes primero','Oldest first'=>'Más antiguos primero','Code A-Z'=>'Código A-Z','Code Z-A'=>'Código Z-A','selected'=>'seleccionados','Select all'=>'Seleccionar todos','Deselect all'=>'Deseleccionar todos','Publish'=>'Publicar','Set as draft'=>'Establecer como borrador','Move to trash'=>'Mover a la papelera','Code'=>'Código','Type'=>'Tipo','Amount'=>'Importe','Description'=>'Descripción','Usage / Limit'=>'Uso / Límite','Revenue'=>'Ingresos','Expiry date'=>'Fecha de caducidad','Status'=>'Estado','Edit coupon'=>'Editar cupón','General'=>'General','Coupon code'=>'Código del cupón','e.g. SUMMER2024'=>'p. ej. VERANO2024','Generate'=>'Generar','Optional description for internal use'=>'Descripción opcional para uso interno','Discount type'=>'Tipo de descuento','Percentage discount'=>'Descuento porcentual','Fixed cart discount'=>'Descuento fijo en el carrito','Fixed product discount'=>'Descuento fijo en el producto','Free shipping'=>'Envío gratis','Usage restrictions'=>'Restricciones de uso','Minimum spend'=>'Gasto mínimo','No minimum'=>'Sin mínimo','Maximum spend'=>'Gasto máximo','No maximum'=>'Sin máximo','Individual use only'=>'Solo uso individual','Cannot be used with other coupons'=>'No se puede usar con otros cupones','Exclude sale items'=>'Excluir artículos en oferta','Search products by name or SKU…'=>'Buscar productos por nombre o SKU…','Limit the coupon to these products. Leave empty to allow all products.'=>'Limita el cupón a estos productos. Déjalo vacío para permitir todos los productos.','Exclude products'=>'Excluir productos','Search products to exclude…'=>'Buscar productos a excluir…','Coupon will not apply when the cart contains these products.'=>'El cupón no se aplicará cuando el carrito contenga estos productos.','Product categories'=>'Categorías de producto','Search categories…'=>'Buscar categorías…','Coupon applies only to products in these categories. Leave empty to allow all categories.'=>'El cupón se aplica solo a productos en estas categorías. Déjalo vacío para permitir todas las categorías.','Exclude categories'=>'Excluir categorías','Search categories to exclude…'=>'Buscar categorías a excluir…','Coupon will not apply to products in these categories.'=>'El cupón no se aplicará a productos en estas categorías.','Allowed emails'=>'Emails permitidos','e.g. jane@example.com, *@team.com'=>'p. ej. juan@ejemplo.com, *@equipo.com','Comma- or newline-separated. Wildcards like *@example.com are supported.'=>'Separados por comas o saltos de línea. Se admiten comodines como *@ejemplo.com.','Usage limits'=>'Límites de uso','Usage limit per coupon'=>'Límite de uso por cupón','Unlimited'=>'Ilimitado','Usage limit per user'=>'Límite de uso por usuario','Limit usage to X items'=>'Limitar uso a X artículos','All matching items'=>'Todos los artículos coincidentes','Caps the number of matching items the discount applies to per cart. Only used with product or category restrictions.'=>'Limita el número de artículos coincidentes a los que se aplica el descuento por carrito. Solo se usa con restricciones de producto o categoría.','Usage count'=>'Recuento de uso','Cancel'=>'Cancelar','Save changes'=>'Guardar cambios','Coupon code is required.'=>'Se requiere el código del cupón.','A coupon with this code already exists.'=>'Ya existe un cupón con este código.','Coupon updated!'=>'¡Cupón actualizado!','Coupon created!'=>'¡Cupón creado!','Invalid coupon ID.'=>'ID de cupón no válido.','Coupon not found.'=>'Cupón no encontrado.','Coupon permanently deleted.'=>'Cupón eliminado permanentemente.','Coupon moved to trash.'=>'Cupón movido a la papelera.','Coupon status changed to %s.'=>'Estado del cupón cambiado a %s.','Coupon duplicated!'=>'¡Cupón duplicado!','(deleted product #%d)'=>'(producto eliminado #%d)','(deleted category #%d)'=>'(categoría eliminada #%d)','Customer Analytics'=>'Analíticas de clientes','Invalid request.'=>'Solicitud no válida.','User ID'=>'ID de usuario','Name'=>'Nombre','Email'=>'Email','Order count'=>'Número de pedidos','Total spent (LTV)'=>'Total gastado (LTV)','Average order value'=>'Valor medio del pedido','Recency (days)'=>'Recencia (días)','First order'=>'Primer pedido','Last order'=>'Último pedido','Invalid segment.'=>'Segmento no válido.','Segment'=>'Segmento','R'=>'R